  ('optician-moex-00841', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列青光眼與性別的關係何者正確？', '["隅角開放性青光眼女性比男性多", "隅角閉鎖性青光眼女性比男性多", "隅角開放性青光眼男性比女性多", "隅角閉鎖性青光眼男性比女性多"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00842', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關色素性視網膜炎（retinitispigmentosa）的說明何者錯誤？', '["可能是偶發突變或是遺傳而來", "會有夜盲現象", "周邊視野會漸漸缺損，晚期視力可能嚴重受損", "若早期發現，可用藥物有效治療，恢復視力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00843', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關高度近視導致的斜視問題，下列敘述何者錯誤？', '["因高度近視眼球的變化，會導致上直肌往鼻側偏移", "因高度近視眼球的變化，會導致外直肌往下側偏移", "因高度近視眼外肌的偏移，會導致眼球往外側偏移，形成外斜視", "核磁共振掃描（MRI）影像可以應用於診斷此種疾病"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00844', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '關於驗光生公會，下列敘述何者正確？①全國聯合會理事、監事之當選，不以直轄市、縣（市）公會選派', '["直轄市、縣（市）驗光生公會選派參加全國聯合會之會員代表，以其理事、監事 為限", "驗光生公會由人民團體主管機關主管", "直轄市、縣（市）驗光生公會，由該轄區域內驗光生20人 以上發起組織之", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00845', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有一位媽媽帶著幼稚園中班的女兒來驗光所，稱她女兒在學校視力檢查只能看到 0.3，故要求配鏡矯正近 視，下列驗光生作法何者正確？', '["應於眼科醫師指導下用儀器做非侵入性之眼球屈光狀態測量及相關驗光", "應轉介至社福機構做視覺功能級別鑑定及低視力者輔助器具之教導使用", "應於眼科醫師指導下做一般性近視、遠視、散光之驗光", "應填轉介單轉診給眼科醫師，並不得為之驗光"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00846', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '驗光所之負責驗光人員因故不能執行業務時，應指定合格驗光人員代理之。下列何者正確？', '["所謂合格驗光生，以在驗光人員法第9條所定之機構執行業務3年以上者為限", "代理期間超過半年者，應由被代理者報請公會撤銷執業執照", "代理期間超過45日者，應由被代理者報請原發開業執照機關備查", "代理期間，最長不得逾半年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00847', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關主管機關不得發給執業執照的規定，下列敘述何者錯誤？', '["經撤銷或廢止驗光人員證書", "經廢止驗光人員執業執照未滿2年", "有客觀事實認不能執行業務，經直轄市、縣（市）主管機關邀請相關專科醫師、驗光人員及學者專家組 成小組認定", "如客觀事實認不能執行業務原因消失後，仍得依法規定申請執業執照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00848', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關隱形眼鏡販售驗配之規定，下列敘述何者正確？①隱形眼鏡之保存盒屬於醫療器材，依法不得於網路', '["非藥商不得為隱形眼鏡之販售廣告，且不得藉採訪、報導或以其他不正 當方式為宣傳", "日戴型每日拋棄式裝飾性隱形眼鏡，其販賣業者依法得於電視頻道通路販售", "一般隱 形眼鏡之驗光及配鏡屬於驗光生之業務範圍", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
